#include <stdio.h>
#include <string.h>
#define MAXN 100
#define MAXM 100

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int T, N, M, i, j, k, p, ans;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int A[MAXN][MAXM];
        for (i = 0; i < N; i++) {
            char s[MAXM + 1];
            scanf("%s", s);
            for (j = 0; j < M; j++) {
                A[i][j] = s[j] - '0';
            }
        }
        ans = 0;
        for (p = 0; p < 10; p++) {
            int dp[MAXN][MAXM];
            for (i = 0; i < N; i++) {
                for (j = 0; j < M; j++) {
                    dp[i][j] = 1;
                }
            }
            for (i = 0; i < N; i++) {
                for (j = 0; j < M; j++) {
                    int x = (A[i][j] + p) % 10;
                    if (i > 0) {
                        dp[i][j] = max(dp[i][j], dp[i - 1][j] + (x >= (A[i - 1][j] + p) % 10));
                    }
                    if (j > 0) {
                        dp[i][j] = max(dp[i][j], dp[i][j - 1] + (x >= (A[i][j - 1] + p) % 10));
                    }
                }
            }
            for (i = 0; i < N; i++) {
                for (j = 0; j < M; j++) {
                    ans = max(ans, dp[i][j]);
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

