import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[][] A = new int[N][M];
            for (int i = 0; i < N; i++) {
                String s = sc.next();
                for (int j = 0; j < M; j++) {
                    A[i][j] = s.charAt(j) - '0';
                }
            }
            int ans = 0;
            for (int p = 0; p < 10; p++) {
                int[][] dp = new int[N][M];
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < M; j++) {
                        dp[i][j] = 1;
                    }
                }
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < M; j++) {
                        int x = (A[i][j] + p) % 10;
                        if (i > 0) {
                            dp[i][j] = Math.max(dp[i][j], dp[i - 1][j] + (x >= (A[i - 1][j] + p) % 10 ? 1 : 0));
                        }
                        if (j > 0) {
                            dp[i][j] = Math.max(dp[i][j], dp[i][j - 1] + (x >= (A[i][j - 1] + p) % 10 ? 1 : 0));
                        }
                    }
                }
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < M; j++) {
                        ans = Math.max(ans, dp[i][j]);
                    }
                }
            }
            System.out.println(ans);
        }
    }
}

