const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, M] = readline().split(' ').map(Number);
    const A = [];
    for (let j = 0; j < N; j++) {
        const s = readline();
        A.push(s.split('').map(Number));
    }
    let ans = 0;
    for (let p = 0; p < 10; p++) {
        const dp = Array(N).fill(0).map(() => Array(M).fill(1));
        for (let j = 0; j < N; j++) {
            for (let k = 0; k < M; k++) {
                const x = (A[j][k] + p) % 10;
                if (j > 0) {
                    dp[j][k] = Math.max(dp[j][k], dp[j - 1][k] + (x >= (A[j - 1][k] + p) % 10 ? 1 : 0));
                }
                if (k > 0) {
                    dp[j][k] = Math.max(dp[j][k], dp[j][k - 1] + (x >= (A[j][k - 1] + p) % 10 ? 1 : 0));
                }
            }
        }
        for (let j = 0; j < N; j++) {
            for (let k = 0; k < M; k++) {
                ans = Math.max(ans, dp[j][k]);
            }
        }
    }
    console.log(ans);
}

